"""Structured-API agent: calls HTTP endpoints auto-generated by Reflex's
EventHandlerAPIPlugin from the State event handlers in `state.py`.

The plugin routes every event handler as `POST /_reflex/event/<state>/<name>`
and streams state-delta NDJSON responses. The agent's tool surface is
intentionally REST-shaped; this client maps each tool to the handler
sequence that drives the same flow the UI uses (e.g. `update_order` →
`load_order` + `set_order_status_draft` + `save_order_status`).

Reads happen by triggering a setter handler and reading the resulting
computed-var delta from the response — the plugin recomputes dependent vars
and emits them as part of the same stream.
"""

from __future__ import annotations

import argparse
import json
import os
import time
import uuid

import anthropic
import requests

BASE = os.environ.get("REFLEX_ADMIN_API", "http://localhost:8001")
STATE_PATH = "reflex_admin___state____state"
RX_STATE_SUFFIX = "_rx_state_"
TOKEN = str(uuid.uuid4())


TOOLS = [
    {
        "name": "list_customers",
        "description": "Search customers by last-name substring. Returns up to 100 rows sorted by nb_orders desc.",
        "input_schema": {
            "type": "object",
            "properties": {
                "q": {"type": "string", "description": "Last-name search substring"},
            },
        },
    },
    {
        "name": "list_orders",
        "description": "List orders filtered by customer_id and/or status.",
        "input_schema": {
            "type": "object",
            "properties": {
                "customer_id": {"type": "integer"},
                "status": {"type": "string", "enum": ["ordered", "delivered", "cancelled"]},
            },
        },
    },
    {
        "name": "update_order",
        "description": "Update an order's status.",
        "input_schema": {
            "type": "object",
            "properties": {
                "order_id": {"type": "integer"},
                "status": {"type": "string", "enum": ["ordered", "delivered", "cancelled"]},
            },
            "required": ["order_id", "status"],
        },
    },
    {
        "name": "list_reviews",
        "description": "List reviews filtered by customer_id and/or status.",
        "input_schema": {
            "type": "object",
            "properties": {
                "customer_id": {"type": "integer"},
                "status": {"type": "string", "enum": ["pending", "accepted", "rejected"]},
            },
        },
    },
    {
        "name": "update_review",
        "description": "Update a review's status.",
        "input_schema": {
            "type": "object",
            "properties": {
                "review_id": {"type": "integer"},
                "status": {"type": "string", "enum": ["pending", "accepted", "rejected"]},
            },
            "required": ["review_id", "status"],
        },
    },
]


TASK = (
    "A customer named Smith has complained about a recent order. "
    "1. Find all customers with last name containing Smith. "
    "2. Identify the one with the most orders. "
    "3. Find their most recent order with status ordered. "
    "4. Check if that customer has any pending reviews. "
    "5. Accept all pending reviews for that customer. "
    "6. Mark the order from step 3 as delivered. "
    "Report: customer name, customer ID, order reference, and how many reviews you accepted."
)


def _post(handler: str, args: dict | None = None) -> dict[str, dict]:
    """POST to the plugin-generated endpoint and return a flattened map of
    {var_name -> latest_value} across all delta lines and all sub-states."""
    resp = requests.post(
        f"{BASE}/_reflex/event/{STATE_PATH}/{handler}",
        json=args or {},
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    resp.raise_for_status()
    merged: dict[str, dict] = {}
    for line in resp.text.splitlines():
        if not line.strip():
            continue
        delta = json.loads(line)
        for state_path, state_data in delta.items():
            if not isinstance(state_data, dict):
                continue
            bucket = merged.setdefault(state_path, {})
            for k, v in state_data.items():
                bucket[k] = v
    return merged


def _read_var(merged: dict[str, dict], var: str):
    """Find a state var across all sub-states, returning the latest value."""
    key = var + RX_STATE_SUFFIX
    for state_data in merged.values():
        if key in state_data:
            return state_data[key]
    return None


def _list_customers(q: str) -> list[dict]:
    merged = _post("set_customers_query", {"q": q or ""})
    return _read_var(merged, "customer_rows") or []


def _list_orders(customer_id: int | None, status: str | None) -> list[dict]:
    if customer_id is not None:
        # The orders-for-a-customer flow is via the customer detail page.
        merged = _post("load_customer", {"customer_id": int(customer_id)})
        rows = _read_var(merged, "selected_customer_orders") or []
        if status:
            rows = [o for o in rows if o.get("status") == status]
        return rows
    if status:
        # Orders list page: pick the status tab and read its rows.
        merged = _post("set_orders_tab", {"tab": status})
        return _read_var(merged, "order_rows") or []
    # Neither filter — default to the orders list page's current tab.
    merged = _post("set_orders_tab", {"tab": "ordered"})
    return _read_var(merged, "order_rows") or []


def _update_order(order_id: int, status: str) -> dict:
    _post("load_order", {"order_id": int(order_id)})
    _post("set_order_status_draft", {"status": status})
    merged = _post("save_order_status")
    return _read_var(merged, "selected_order") or {}


def _list_reviews(customer_id: int | None, status: str | None) -> list[dict]:
    merged = _post("set_reviews_status_filter", {"status": status or "pending"})
    rows = _read_var(merged, "review_rows") or []
    if customer_id is not None:
        rows = [r for r in rows if r.get("customer_id") == int(customer_id)]
    return rows


def _update_review(review_id: int, status: str) -> dict:
    _post("select_review", {"review_id": int(review_id)})
    if status == "accepted":
        _post("accept_review")
    elif status == "rejected":
        _post("reject_review")
    else:
        # The UI has no "set back to pending" handler; the agent's task only
        # ever moves reviews to accepted/rejected, so this path is unused.
        raise ValueError(f"unsupported review status {status!r}")
    # accept_review/reject_review reset selected_review_id to -1; re-select
    # so the caller sees the mutated review, not an empty dict.
    merged = _post("select_review", {"review_id": int(review_id)})
    return _read_var(merged, "selected_review") or {}


def execute_tool(name: str, args: dict):
    if name == "list_customers":
        return _list_customers(args.get("q", ""))
    if name == "list_orders":
        return _list_orders(args.get("customer_id"), args.get("status"))
    if name == "update_order":
        return _update_order(args["order_id"], args["status"])
    if name == "list_reviews":
        return _list_reviews(args.get("customer_id"), args.get("status"))
    if name == "update_review":
        return _update_review(args["review_id"], args["status"])
    raise ValueError(f"unknown tool {name}")


def run_trial(model: str) -> dict:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": TASK}]
    total_input = 0
    total_output = 0
    tool_calls = 0
    start = time.time()
    final = ""

    while True:
        resp = client.messages.create(
            model=model,
            max_tokens=4096,
            tools=TOOLS,
            messages=messages,
        )
        total_input += resp.usage.input_tokens
        total_output += resp.usage.output_tokens

        if resp.stop_reason == "end_turn":
            final = "".join(b.text for b in resp.content if b.type == "text")
            break

        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                tool_calls += 1
                print(f"  Tool: {block.name}({json.dumps(block.input)})")
                result = execute_tool(block.name, block.input.copy())
                result_str = json.dumps(result)
                if len(result_str) > 4000:
                    result_str = result_str[:4000] + "...(truncated)"
                tool_results.append(
                    {
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result_str,
                    }
                )
        messages.append({"role": "user", "content": tool_results})

    return {
        "model": model,
        "elapsed_seconds": round(time.time() - start, 2),
        "input_tokens": total_input,
        "output_tokens": total_output,
        "total_tokens": total_input + total_output,
        "tool_calls": tool_calls,
        "final_answer": final,
    }


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument(
        "--model",
        default="claude-sonnet-4-20250514",
        help="Anthropic model id (e.g. claude-sonnet-4-20250514, claude-haiku-4-5-20251001)",
    )
    ap.add_argument(
        "--out",
        default=None,
        help="Output JSON path (default: api_agent_<model-slug>.json)",
    )
    args = ap.parse_args()

    result = run_trial(args.model)

    print()
    print(f"Done in {result['elapsed_seconds']}s")
    print(f"Tool calls: {result['tool_calls']}")
    print(f"Tokens: {result['input_tokens']} in / {result['output_tokens']} out")
    print()
    print(result["final_answer"])

    out = args.out or f"api_agent_{args.model.replace('/', '-')}.json"
    with open(out, "w") as f:
        json.dump(result, f, indent=2)
    print(f"\nWrote {out}")


if __name__ == "__main__":
    main()
